// EPSO AD5 Digital Skills — Question bank
// Mapped to DigComp 2.2 (JRC128415). 168 items across all 21 competences.
// Each: {i:id, c:competence "x.y", t:topic, d:difficulty 1-3, q:stem, o:[4 options], a:correct index, e:explanation}

window.QUESTIONS = [
    { i: "1.1.1", c: "1.1", t: "Search operators", d: 1, q: "You need to find PDF reports about EU asylum policy from official EU institutions only. Which approach is most efficient?", o: ["Type 'EU asylum reports' in a general search engine and skim the first 30 results", "Use site:europa.eu and filetype:pdf operators with your keywords", "Search inside Wikipedia first to find primary sources", "Use a generative AI chatbot and ask for the latest reports"], a: 1, e: "Search operators (site:, filetype:, intitle:) narrow results to authoritative sources without skimming. Generative AI can hallucinate citations; Wikipedia is secondary; broad search wastes time." },
    { i: "1.1.2", c: "1.1", t: "Recommender systems", d: 2, q: "You notice your social-media feed shows almost only views you already agree with. The DigComp 2.2 framework calls this phenomenon a:", o: ["Phishing trap", "Filter bubble created by algorithmic personalisation", "Cookie wall", "Distributed denial-of-service effect"], a: 1, e: "A filter bubble arises when recommender algorithms personalise content based on prior engagement, narrowing exposure to alternative views." },
    { i: "1.1.3", c: "1.1", t: "Sponsored vs organic", d: 1, q: "In a search-engine results page, which signal most reliably distinguishes a paid advertisement from an organic result?", o: ["The result has a higher position on the page", "An explicit 'Sponsored' or 'Ad' label", "The URL contains 'https'", "The site has a professional design"], a: 1, e: "Search engines are legally required to label paid placements. Position, HTTPS and design quality are not reliable indicators of whether a result is paid." },
    { i: "1.1.4", c: "1.1", t: "AI text recognition", d: 2, q: "Which of the following is the LEAST reliable way to determine whether a text was generated by an AI system?", o: ["Cross-checking specific verifiable factual claims in the text", "Looking for vague generalities and unusually polished but generic phrasing", "Running it through an automated 'AI-detector' tool", "Comparing the writing style to the supposed author's known work"], a: 2, e: "Automated AI-detector tools have high false-positive and false-negative rates and are not considered reliable. Cross-checking facts, examining style, and detecting generic phrasing are more dependable signals." },
    { i: "1.1.5", c: "1.1", t: "Voice assistants", d: 1, q: "What is a key privacy consideration when using a voice assistant to search for information?", o: ["Voice queries are encrypted end-to-end and never leave the device", "Voice queries may be transmitted to the provider's servers and retained as data", "Voice search results are always more accurate than typed search", "Voice assistants do not use cookies"], a: 1, e: "Voice queries are typically processed in the cloud and may be retained, reviewed, and used for service improvement depending on provider policies." },
    { i: "1.1.6", c: "1.1", t: "Search strategy", d: 1, q: "You are researching an unfamiliar legal topic. What is the most effective first step in building a search strategy?", o: ["Start with the most specific technical phrase you can think of", "Identify a few authoritative sources for the domain (e.g. EUR-Lex for EU law) and search there", "Use only one search engine to keep results consistent", "Read every result on the first page in order"], a: 1, e: "Identifying authoritative domain-specific sources first (EUR-Lex, official journals, accredited databases) is more efficient than narrow keyword guessing or exhaustive reading." },
    { i: "1.1.7", c: "1.1", t: "RSS feeds", d: 2, q: "Which technology is best suited for monitoring updates from many official websites without manually visiting each one?", o: ["A virtual private network (VPN)", "An RSS feed reader subscribing to each site's feed", "A persistent browser cookie", "A bookmark folder"], a: 1, e: "RSS aggregates updates from many sources into a single feed. VPNs route traffic; cookies store state; bookmarks still require manual visits." },
    { i: "1.1.8", c: "1.1", t: "Direct ID search", d: 1, q: "On the EUR-Lex website, you know the exact CELEX number of a legal act. The most efficient retrieval method is:", o: ["Browse alphabetically through the directory of legal acts", "Use the 'Quick search' field with the CELEX number", "Type the title into a general web search engine", "Email the EUR-Lex helpdesk"], a: 1, e: "When you have a unique identifier (CELEX, DOI, ISBN), direct ID search is the fastest path." },
    { i: "1.2.1", c: "1.2", t: "Malinformation", d: 2, q: "An employee leaks a genuine internal memo to an external journalist with the explicit aim of damaging a colleague's reputation. Under the UNESCO information-disorder taxonomy, this is best classified as:", o: ["Misinformation", "Disinformation", "Malinformation", "Whistleblowing"], a: 2, e: "Malinformation = information based on reality, used to inflict harm. Disinformation requires the information itself to be false; misinformation is false but unintentional. Whistleblowing concerns disclosure of wrongdoing in the public interest." },
    { i: "1.2.2", c: "1.2", t: "Misinformation vs disinformation", d: 2, q: "A friend forwards you a health claim that is factually wrong. The friend genuinely believes it is true. By UNESCO's definition this is:", o: ["Disinformation, because the claim is false", "Misinformation, because there is no intent to harm", "Malinformation, because it is shared widely", "Propaganda, because it influences opinion"], a: 1, e: "Misinformation = false content shared without intent to harm. Disinformation requires deliberate intent. The classification depends on intent, not on how widely it spreads." },
    { i: "1.2.3", c: "1.2", t: "AI hallucination", d: 2, q: "A generative-AI chatbot confidently cites a 2023 Court of Justice ruling that turns out not to exist. This output is best described as:", o: ["A bias in the training data", "A hallucination", "A prompt injection", "A privacy breach"], a: 1, e: "A hallucination is fluent, confident output that is unsupported by the model's input or by reality. Bias is systematic skew; prompt injection is adversarial input." },
    { i: "1.2.4", c: "1.2", t: "Source triangulation", d: 1, q: "You see a striking statistic on a blog. The most rigorous next step before citing it is:", o: ["Share it because the blog has many followers", "Trace it back to its primary source and check the methodology", "Check whether other blogs repeat the same statistic", "Trust it if a generative AI tool also produces a similar figure"], a: 1, e: "Tracing a claim to its primary source is the gold standard. Repetition across secondary sources can amplify error; AI tools may regurgitate the same flawed source." },
    { i: "1.2.5", c: "1.2", t: "Deepfake indicators", d: 2, q: "Which of the following is the LEAST useful indicator that a video might be a deepfake?", o: ["Inconsistent lighting on the face vs the background", "Unnatural blinking or mouth synchronisation", "The video is shared on social media", "Audio that does not match lip movement on close inspection"], a: 2, e: "Sharing on social media is irrelevant to authenticity — both genuine and fake content circulate there. Lighting, blinking, and audio sync are recognised technical artefacts of synthetic media." },
    { i: "1.2.6", c: "1.2", t: "Primary vs secondary", d: 1, q: "For research on a recent EU regulation, which counts as the primary source?", o: ["A news analysis explaining the regulation", "The published text of the regulation in the Official Journal", "An academic article reviewing the regulation's impact", "A press release summarising the regulation"], a: 1, e: "A primary source is the original document itself. News analyses, press releases, and academic reviews are secondary." },
    { i: "1.2.7", c: "1.2", t: "Chart deception", d: 2, q: "A chart shows a 'spectacular' rise in cases. Which feature should make you most cautious before drawing conclusions?", o: ["The chart uses colour to highlight one bar", "The y-axis starts at a high value (not zero) without a clear break indicator", "The chart is in PDF format", "The data points are marked with circles"], a: 1, e: "A truncated y-axis without a break indicator can visually exaggerate small differences. Colour, format, and marker style are stylistic, not deceptive in themselves." },
    { i: "1.2.8", c: "1.2", t: "Bias vs hallucination", d: 3, q: "An AI résumé screener consistently rates equally qualified male candidates higher than female ones. This is most accurately described as:", o: ["A hallucination, because the output is wrong", "A bias, reflecting skews in the training data or model", "A prompt injection", "A jailbreak"], a: 1, e: "Bias is systematic, patterned skew in outputs reflecting training-data or design choices. A hallucination is a fabricated fact, not a systematic group-level error." },
    { i: "1.3.1", c: "1.3", t: "Backup 3-2-1", d: 1, q: "The widely recommended '3-2-1' backup rule means:", o: ["3 backups daily, 2 cloud copies, 1 USB stick", "3 copies of data, on 2 different media, with 1 stored off-site", "3 minutes between saves, 2 folders, 1 owner", "3 users, 2 passwords, 1 admin"], a: 1, e: "3-2-1 = three total copies, on at least two different media types, with at least one stored off-site. It protects against device failure, ransomware, and physical disasters." },
    { i: "1.3.2", c: "1.3", t: "Cloud trade-offs", d: 1, q: "Which of the following is NOT a recognised advantage of cloud storage over purely local storage?", o: ["Access from multiple devices", "Built-in redundancy across data centres", "Guaranteed independence from any third-party access", "Easier collaboration through link-sharing"], a: 2, e: "Cloud storage relies on a third-party provider, who has technical access to the underlying systems and may be subject to legal requests." },
    { i: "1.3.3", c: "1.3", t: "EXIF metadata", d: 2, q: "You take a photo on your phone and email it to a colleague. What hidden information may travel with the file?", o: ["Only the timestamp", "EXIF metadata, which can include GPS coordinates, device model, and timestamp", "The phone's IMEI number", "The recipient's IP address"], a: 1, e: "Photos typically embed EXIF metadata: device model, settings, date/time, and (if location services were enabled) GPS coordinates. Stripping EXIF before sharing is good practice for sensitive photos." },
    { i: "1.3.4", c: "1.3", t: "Datafication", d: 2, q: "DigComp 2.2 introduces 'datafication awareness' — the recognition that:", o: ["All data should be stored as numbers", "Everyday digital activities generate data that organisations can collect, analyse and exploit", "Datafication is illegal under the GDPR", "Only governments collect personal data"], a: 1, e: "Datafication describes how routine digital interactions (clicks, locations, voice queries) are turned into datasets. It is not inherently illegal but raises questions GDPR seeks to address." },
    { i: "1.3.5", c: "1.3", t: "File naming", d: 1, q: "Which file-naming convention is best for a shared archive used over many years?", o: ["report final FINAL v3 (use this).docx", "2024-03-15_asylum-policy-report_v02.docx", "Asylum Report (Maria's copy).docx", "report.docx"], a: 1, e: "ISO-style date prefix, descriptive content, and version number give chronological sortability and unambiguous identification." },
    { i: "1.3.6", c: "1.3", t: "Open data", d: 2, q: "A dataset is described as 'open data'. The defining requirement is that:", o: ["It is free to download", "It is published under a licence permitting reuse, redistribution and modification", "It contains no personal data", "It is hosted by a public authority"], a: 1, e: "'Open' refers to the licence — reuse, redistribution and modification must be permitted. Free access alone is not enough; many freely viewable datasets are still copyrighted." },
    { i: "1.3.7", c: "1.3", t: "Cache vs cookies", d: 2, q: "Which best distinguishes a browser cache from cookies?", o: ["Cache stores resource copies for speed; cookies store state and identity for sessions and tracking", "Cache is encrypted; cookies are not", "Cache is server-side; cookies are client-side", "They are the same thing"], a: 0, e: "Cache holds local copies of fetched resources to speed up repeat loads. Cookies are small data items used to maintain login state, preferences, and (often) tracking identifiers." },
    { i: "1.3.8", c: "1.3", t: "Permissions check", d: 1, q: "You are about to upload sensitive draft policy notes to a shared team folder. The most important first check is:", o: ["Whether the folder has a recognisable colour icon", "Who has access to the folder and at what permission level", "The size of the file", "Whether the file name contains spaces"], a: 1, e: "Verifying access scope and permissions prevents inadvertent disclosure to people who should not see drafts. Visual cues like icons are not authoritative." },
    { i: "2.1.1", c: "2.1", t: "Channel choice", d: 1, q: "You need to deliberate carefully with five colleagues across three time zones on a complex policy text. Which channel is most appropriate as the main forum?", o: ["A video call at 22:00 for some, 09:00 for others", "An asynchronous shared document with structured comment threads", "A long single-thread email reply-all", "A series of brief instant messages"], a: 1, e: "Asynchronous, structured collaboration suits complex deliberation across time zones — it respects working hours and lets each contributor reflect." },
    { i: "2.1.2", c: "2.1", t: "Sync vs async", d: 1, q: "Which task is best handled synchronously rather than asynchronously?", o: ["Reviewing a 40-page draft report", "Recording a one-hour briefing for absent colleagues", "A short urgent decision requiring two-way clarification within 10 minutes", "Compiling translation suggestions over a week"], a: 2, e: "Synchronous communication is preferable when interactivity and quick clarification are essential. Document review, recordings, and multi-day compilation are paradigm asynchronous tasks." },
    { i: "2.1.3", c: "2.1", t: "AI meeting assistant", d: 2, q: "Your office introduces an AI meeting-assistant that transcribes and summarises calls. What is the most important professional consideration before using it on a sensitive call?", o: ["Whether it integrates with your calendar", "Whether participants are informed and have consented, and whether the data flow complies with your organisation's data-protection rules", "Whether it produces summaries in your preferred language", "Whether it has a dark-mode interface"], a: 1, e: "Transparency, consent, and compliance are decisive — particularly when calls contain personal or confidential data. Convenience features are secondary." },
    { i: "2.1.4", c: "2.1", t: "Bandwidth issue", d: 2, q: "During a video call, audio is clear but participants' video freezes. The likely bottleneck is:", o: ["Insufficient bandwidth on the network connection", "Encryption overhead", "An out-of-date browser", "Time-zone mismatch"], a: 0, e: "Video streams demand much more bandwidth than audio. Video freezes first when bandwidth is tight, while audio (smaller, prioritised) remains clear." },
    { i: "2.1.5", c: "2.1", t: "Hybrid inclusion", d: 2, q: "A hybrid team meets weekly with some staff in the room and some remote. Which practice best supports inclusion of remote participants?", o: ["A single shared microphone in the room and only people in the room speak", "Each participant joins the video call from their own device, with a clear chair facilitating turns", "Remote participants email questions afterward", "Limit remote participants to listening only"], a: 1, e: "'One person, one tile' on the call equalises presence and audibility. Centralised mics tend to favour in-room voices." },
    { i: "2.1.6", c: "2.1", t: "Email vs chat", d: 1, q: "Which message is best sent by email rather than instant chat?", o: ["A formal communication of a final decision to be archived in the case file", "A quick 'Are you free at 3?' message", "A reaction to a colleague's joke", "A reminder to check a shared folder in the next minute"], a: 0, e: "Email is the appropriate channel for formal, archivable communications and decisions that need a durable record." },
    { i: "2.1.7", c: "2.1", t: "Sensitive data on chat", d: 2, q: "You receive a chat message with confidential personal data of an applicant. The professional response is to:", o: ["Reply on chat using only first names to be safer", "Continue the discussion on chat because chat is private", "Move the discussion to an authorised, more secure channel and avoid further sharing of identifiable data on the original chat", "Forward the chat to your personal email so you can keep a copy"], a: 2, e: "Personal data should be processed only via authorised, secured channels. Forwarding to personal email creates a new uncontrolled processing instance and a potential GDPR breach." },
    { i: "2.1.8", c: "2.1", t: "Out-of-office", d: 1, q: "What information should an out-of-office auto-reply NOT include?", o: ["Your return date", "An alternative contact for urgent matters", "Your detailed travel itinerary and personal mobile number", "A brief acknowledgement of receipt"], a: 2, e: "Auto-replies are sent to anyone, including senders you do not know. Detailed itineraries and personal numbers are over-disclosures and can be misused." },
    { i: "2.2.1", c: "2.2", t: "To/Cc/Bcc", d: 1, q: "You must email a draft briefing to twelve external experts who do not know each other. Which addressing approach best protects their personal data while still allowing replies?", o: ["To: all experts", "Bcc: all experts; To: yourself", "Cc: all experts", "Bcc: yourself; To: all experts"], a: 1, e: "Putting recipients in Bcc prevents disclosure of their email addresses to one another — emails are personal data. Putting yourself in To gives the message a valid To: header without exposing the others." },
    { i: "2.2.2", c: "2.2", t: "Anyone-with-link", d: 2, q: "You share a cloud document via 'Anyone with the link can edit'. What is the principal risk?", o: ["The document will be slower to load", "Anyone who obtains the link — by forwarding, screenshot, browser history — can edit and you cannot tell who", "The document size will be limited", "The document cannot be opened on mobile"], a: 1, e: "Open-link permissions transfer access to anyone who acquires the link, with no audit trail of who viewed or edited." },
    { i: "2.2.3", c: "2.2", t: "Attribution", d: 1, q: "You quote a paragraph from a colleague's report in an internal newsletter. The minimum professional practice is to:", o: ["Reword it slightly so attribution is unnecessary", "Cite the author, title, and date of the original report", "Ask the IT department first", "Remove any quotation marks to make the text flow"], a: 1, e: "Attribution is required regardless of medium. Slight rewording without attribution is plagiarism. IT permission is unrelated to authorship credit." },
    { i: "2.2.4", c: "2.2", t: "Restricted material", d: 2, q: "A colleague forwards you an email marked 'Restricted' from a third party. The appropriate action is to:", o: ["Forward it on to anyone you think should see it", "Do not redistribute it; check whether the original sender authorised secondary sharing", "Print it and leave it in the kitchen for the team", "Reply-all asking who else should see it"], a: 1, e: "Restricted markings indicate restricted distribution. Forwarding without authorisation breaches the originator's instruction." },
    { i: "2.2.5", c: "2.2", t: "Expiring links", d: 2, q: "What is a privacy benefit of using time-limited or expiring share links rather than permanent ones?", o: ["They reduce file size", "They cannot be opened on mobile", "They limit the window of exposure if a link leaks or is forwarded", "They make the file public"], a: 2, e: "An expiring link bounds the period during which a leaked or forwarded link remains exploitable." },
    { i: "2.2.6", c: "2.2", t: "Version control", d: 2, q: "A team is co-authoring a report. Which approach minimises lost edits and confusion?", o: ["Each person keeps their own copy and emails versions back and forth", "Use a single source-of-truth document with built-in version history and named co-editors", "Use a printed master copy", "Combine paragraphs from many copies at the end"], a: 1, e: "A live, version-controlled document with named editors avoids fork-and-merge problems entirely. Email round-trips are where edits get lost." },
    { i: "2.2.7", c: "2.2", t: "Reply-all etiquette", d: 1, q: "You are added to a 200-person internal mailing list. You disagree with one message. The most appropriate response is to:", o: ["Reply-all so everyone sees your view", "Reply only to the original sender, or use the appropriate moderated channel", "Forward the disagreement to your manager and copy the list", "Unsubscribe and ignore"], a: 1, e: "Reply-all on large lists creates noise and notification cascades. A direct reply keeps the discussion proportionate." },
    { i: "2.2.8", c: "2.2", t: "Citing AI outputs", d: 3, q: "You incorporate a paragraph from a generative-AI chatbot into a report. The most professionally responsible approach is to:", o: ["Treat the AI as a co-author and cite it like a colleague", "Disclose use of the AI tool in line with your organisation's policy and verify the factual content independently", "Hide the use because AI is unreliable", "Copy the text without disclosure if it sounds plausible"], a: 1, e: "Disclose-and-verify is the emerging professional norm and is consistent with most organisational AI policies. AI outputs lack authorship in the legal/academic sense." },
    { i: "2.3.1", c: "2.3", t: "eIDAS", d: 2, q: "What is the principal purpose of the EU's eIDAS framework?", o: ["To provide free Wi-Fi in public buildings", "To enable secure cross-border electronic identification and trust services (e-signatures, e-seals, time-stamps) within the EU", "To replace national identity cards with a single EU card", "To regulate social-media content"], a: 1, e: "eIDAS (Reg. 910/2014, updated 2024) sets EU-wide rules for electronic identification and trust services so that an e-signature recognised in one Member State is recognised in others." },
    { i: "2.3.2", c: "2.3", t: "ECI", d: 1, q: "The European Citizens' Initiative is best described as:", o: ["A petition mechanism letting EU citizens invite the Commission to propose legislation, subject to thresholds", "A binding referendum tool", "A consumer-complaint platform", "A funding scheme for civil-society organisations"], a: 0, e: "The ECI lets at least one million citizens from a minimum number of Member States invite the Commission to make a legislative proposal. It is non-binding." },
    { i: "2.3.3", c: "2.3", t: "Astroturfing", d: 2, q: "A 'grassroots' online campaign turns out to have been organised and paid for by a single corporate sponsor while presenting itself as spontaneous citizen action. This practice is called:", o: ["Trolling", "Astroturfing", "Lobbying", "Whistleblowing"], a: 1, e: "Astroturfing fakes grassroots support to manipulate public discourse. Lobbying is openly representing an interest; trolling is disruptive online behaviour; whistleblowing exposes wrongdoing." },
    { i: "2.3.4", c: "2.3", t: "Digital inclusion", d: 2, q: "A municipal service moves to 'digital by default'. Which step best addresses the digital-inclusion risk?", o: ["Removing all paper processes immediately to force adoption", "Maintaining accessible alternative channels (phone, in-person) and offering digital-skills support for those who need it", "Charging fees for the paper channel", "Limiting the digital service to working hours"], a: 1, e: "Digital-by-default works only if no-one is excluded. Maintaining alternative channels and skills support is consistent with the EU Digital Decade target." },
    { i: "2.3.5", c: "2.3", t: "Have Your Say", d: 1, q: "You want to provide formal input on a draft EU regulation. The official channel is:", o: ["Posting on social media", "The 'Have Your Say' portal on the Commission's website", "Sending an email to any random EU institution", "Calling Europe Direct"], a: 1, e: "'Have Your Say' is the Commission's public-consultation portal. Social-media posts are not formal input; Europe Direct is for general information requests." },
    { i: "2.3.6", c: "2.3", t: "eID security", d: 2, q: "A national eID card lets a citizen log in to a public-service portal. What is the typical security model?", o: ["A single password stored on the eID", "Two-factor authentication: possession of the card plus knowledge of a PIN, often combined with a card reader or NFC phone", "Biometrics only", "No authentication, only identity disclosure"], a: 1, e: "eID schemes generally rely on possession of the card and knowledge of a PIN — a classic two-factor model — with cryptographic certificates on the card." },
    { i: "2.3.7", c: "2.3", t: "Open government data", d: 1, q: "Why does the EU promote open public-sector data?", o: ["To replace the need for national statistical offices", "To enable transparency, reuse for innovation, and accountability", "To make all government databases free of personal-data rules", "Because data centres are cheaper than archives"], a: 1, e: "The Open Data Directive (2019/1024) frames open public-sector data as a driver of transparency, innovation and accountability — distinct from GDPR obligations." },
    { i: "2.3.8", c: "2.3", t: "Computational propaganda", d: 3, q: "A coordinated network of automated accounts amplifies a single hashtag to make a fringe view appear mainstream. The most precise label is:", o: ["Targeted advertising", "Computational propaganda using bots / inauthentic coordinated behaviour", "Search engine optimisation", "Content moderation"], a: 1, e: "Computational propaganda — algorithmic amplification, often via bots and coordinated inauthentic behaviour — is a recognised category in EU disinformation policy." },
    { i: "2.4.1", c: "2.4", t: "Track changes", d: 1, q: "In a long collaborative document, what is the main professional advantage of using 'track changes' (revision marks)?", o: ["It reduces the file size", "It provides a transparent, attributable trail of edits that other collaborators can review and accept or reject", "It encrypts the document", "It removes formatting differences"], a: 1, e: "Track changes makes authorship of edits explicit and reversible — essential for collaborative legal or policy drafting." },
    { i: "2.4.2", c: "2.4", t: "Comments vs edits", d: 2, q: "During review, you want to suggest a wording change without altering the master text. The most appropriate tool is:", o: ["A comment (or suggestion mode)", "Direct in-line editing", "A separate email", "A printed annotation"], a: 0, e: "Comments and suggestion modes propose changes that the author can accept or reject. Direct edits without consent overwrite authorship." },
    { i: "2.4.3", c: "2.4", t: "Merge conflicts", d: 1, q: "What is the main risk if two people work on the same offline copy of a Word document simultaneously and email versions back and forth?", o: ["The fonts will change", "Edits made by one person will overwrite or be lost relative to the other's, depending on which version is merged later", "The document will become encrypted", "The file size will double"], a: 1, e: "Without a single source of truth, parallel offline edits create merge conflicts and lost work. Live co-editing avoids this." },
    { i: "2.4.4", c: "2.4", t: "Kanban WIP limits", d: 2, q: "Your team uses a Kanban board. The 'work-in-progress' (WIP) limit on a column is intended to:", o: ["Force everyone to work faster", "Prevent overload by capping how many tasks can be in progress at once, surfacing bottlenecks", "Encrypt the board", "Hide tasks from external viewers"], a: 1, e: "WIP limits are a core Kanban discipline. By capping in-progress work they make bottlenecks visible and reduce context-switching." },
    { i: "2.4.5", c: "2.4", t: "Whiteboards for ideation", d: 1, q: "For an early-stage brainstorming session with a hybrid team, the most suitable tool is:", o: ["A formal Word document", "A shared online whiteboard with sticky notes", "A printed agenda", "A spreadsheet"], a: 1, e: "Whiteboards support visual, non-linear, low-friction ideation and let everyone contribute simultaneously." },
    { i: "2.4.6", c: "2.4", t: "Hybrid norms", d: 2, q: "Which working agreement most reduces friction in a hybrid team?", o: ["Always meet in person whenever possible", "Establish 'cameras-on for discussion, cameras-off for status' and document decisions in writing for absent colleagues", "Forbid asynchronous decisions", "Require everyone to be online 9-to-17 across all time zones"], a: 1, e: "Explicit norms about when to use which channel, and durable written records of decisions, are documented best practice for hybrid working in DigComp 2.2's Annex 3." },
    { i: "2.4.7", c: "2.4", t: "AI in collaboration", d: 3, q: "You and a colleague co-author a brief using a generative-AI assistant. Which practice is most aligned with DigComp 2.2 guidance on AI-supported collaboration?", o: ["Each person privately uses the AI; you do not discuss it", "Agree as a team how AI will be used, document the use, and verify factual outputs together", "Use the AI to make all decisions automatically", "Avoid documenting any AI use"], a: 1, e: "Team-level transparency, documentation, and human verification are the governance-aligned approach. Hidden use undermines trust and accountability." },
    { i: "2.4.8", c: "2.4", t: "Permissions hygiene", d: 2, q: "A team wiki has accumulated dozens of editor accounts over years, including for people who have left. The best hygiene practice is:", o: ["Leave them as historical record", "Periodically review and revoke access for departed or non-active users", "Add more editors so the wiki stays alive", "Set the wiki to public-edit"], a: 1, e: "Periodic access review (joiner-mover-leaver) is a basic security and information-governance control — abandoned accounts are common breach vectors." },
    { i: "2.5.1", c: "2.5", t: "All caps", d: 1, q: "A short message in ALL CAPS sent in a professional chat is generally interpreted as:", o: ["Important and urgent in a neutral way", "Shouting or anger", "A formatting error", "A foreign-language quotation"], a: 1, e: "Online netiquette has long treated all-caps as shouting. For emphasis, use bold or italics; for urgency, say so explicitly." },
    { i: "2.5.2", c: "2.5", t: "Intercultural", d: 2, q: "You are working with colleagues across many EU countries. Which practice best supports respectful intercultural communication?", o: ["Use idioms from your own language to add colour", "Prefer plain, literal language; clarify acronyms; be patient with non-native speakers", "Speak louder on calls", "Avoid emoji entirely"], a: 1, e: "Plain language and explicit acronyms are pillars of inclusive professional communication, especially in multilingual EU contexts." },
    { i: "2.5.3", c: "2.5", t: "Bystander response", d: 2, q: "You witness a colleague being personally attacked in a public team channel. The professionally appropriate response is to:", o: ["Ignore it because it is not your business", "Privately support the colleague, do not amplify the attack, and report it through the proper internal channel", "Reply in the same channel with an even harsher attack on the harasser", "Screenshot it and post it to social media"], a: 1, e: "Bystander best practice is to support the target, avoid amplifying the abuse, and use formal reporting channels." },
    { i: "2.5.4", c: "2.5", t: "Inclusive salutations", d: 1, q: "Which is an example of inclusive professional written communication?", o: ["Addressing a mixed group as 'Dear Sirs'", "Addressing a group as 'Dear colleagues' or 'Dear all'", "Using only first names to seem informal", "Avoiding any salutation"], a: 1, e: "Gender-neutral, role-appropriate salutations are inclusive defaults. 'Dear Sirs' assumes a single gender." },
    { i: "2.5.5", c: "2.5", t: "Accessible posts", d: 2, q: "You publish an internal social post containing an infographic with key figures. Which practice supports accessibility?", o: ["Posting only the image, since visuals communicate faster", "Adding alternative text describing the figures, and including the key data in the post text", "Using bright colours only", "Posting the image as a screenshot of a screenshot"], a: 1, e: "Alt-text and an accompanying text version make content perceivable to screen-reader users and to anyone whose images do not load — a WCAG 2.2 baseline expectation." },
    { i: "2.5.6", c: "2.5", t: "Emoji register", d: 1, q: "In a formal letter to an external authority, the appropriate use of emoji is:", o: ["Liberal, to convey friendliness", "Reserved or absent — formal correspondence follows conventional written register", "Required at every paragraph", "Only at the salutation"], a: 1, e: "Register matters. Emoji are typical in chat and informal messages; formal correspondence with authorities follows conventional written norms." },
    { i: "2.5.7", c: "2.5", t: "Public posts as staff", d: 2, q: "You post a strongly-worded political opinion on your personal social-media account. As an EU staff member, the most prudent consideration is:", o: ["Personal accounts are entirely separate from professional duties", "Statements you make publicly online may still be associated with your role and may be subject to your institution's code of conduct on neutrality and reserve", "Personal accounts cannot be screenshotted", "Free speech online has no professional implications"], a: 1, e: "Staff regulations in EU institutions include duties of loyalty and discretion; public posts are seldom truly 'private'. Codes of conduct often address external statements." },
    { i: "2.5.8", c: "2.5", t: "Right to disconnect", d: 2, q: "A colleague messages you outside working hours and demands a reply because the chat shows you 'online'. The appropriate professional norm is to:", o: ["Reply immediately whatever the hour", "Recognise the right to disconnect and respond in working hours unless a genuine emergency", "Switch your status to invisible permanently", "Reply only with an emoji"], a: 1, e: "The right to disconnect (recognised in DigComp 2.2's RW examples) protects rest periods. Genuine emergencies are an exception, not the default." },
    { i: "2.6.1", c: "2.6", t: "Active vs passive footprint", d: 2, q: "Which is an example of a PASSIVE digital footprint?", o: ["A blog post you publish", "Tracking cookies that record your browsing patterns without explicit posting", "An email you send", "A photo you upload"], a: 1, e: "Active footprints come from intentional posts and contributions. Passive footprints are generated by tools observing you (cookies, telemetry, location data) often without conscious action." },
    { i: "2.6.2", c: "2.6", t: "Right to erasure", d: 2, q: "Under GDPR Article 17 ('right to erasure'), a data subject may request deletion of their personal data when:", o: ["They feel like it, in all circumstances, with no exceptions", "The data are no longer necessary for the purposes for which they were collected, or consent is withdrawn, etc., subject to defined exceptions", "Only if the data were inaccurate", "Only if the data were sensitive"], a: 1, e: "Article 17 lists specific grounds (no longer necessary, consent withdrawn, unlawful processing) and explicit exceptions (e.g. freedom of expression, legal obligation). It is not absolute." },
    { i: "2.6.3", c: "2.6", t: "Inferred personal data", d: 3, q: "A platform infers from your activity that you may be pregnant — even though you never disclosed it. Under GDPR, this inferred information is:", o: ["Not personal data because you did not provide it", "Personal data, and may be 'special-category' (health) data depending on context — fully within GDPR scope", "Subject only to the platform's terms of service", "Public information"], a: 1, e: "Inferred and observed data about an identifiable person are personal data. Health-related inferences engage Article 9 special-category protections." },
    { i: "2.6.4", c: "2.6", t: "SSO trade-off", d: 2, q: "You sign in to many services using a single 'Login with X' provider. The main trade-off is:", o: ["You always get faster service", "Convenience and fewer passwords vs concentration of risk and cross-site profiling by the identity provider", "Lower battery use", "Improved encryption"], a: 1, e: "SSO reduces password reuse and friction but consolidates a high-value target and shares identity signals with the provider." },
    { i: "2.6.5", c: "2.6", t: "Personas", d: 2, q: "You maintain a professional LinkedIn profile and a separate gaming-community pseudonym. This is best described as managing:", o: ["Two separate legal identities", "Multiple digital personas tied to one underlying identity, with different audiences and disclosures", "Two unrelated accounts that are legally invisible to each other", "An illegal practice under GDPR"], a: 1, e: "Maintaining context-appropriate personas is normal digital-identity practice. The accounts can still be legally and technically linked." },
    { i: "2.6.6", c: "2.6", t: "Self-audit", d: 1, q: "Old, embarrassing posts surface during a job application. A reasonable proactive practice is to:", o: ["Demand the internet take them down", "Periodically search your own name, review your account privacy settings, and decide what to delete or restrict", "Delete every social-media account", "Sue the search engine"], a: 1, e: "Self-audit (search yourself, review settings, prune content) is the practical baseline. Erasure rights exist but are bounded." },
    { i: "2.6.7", c: "2.6", t: "Profiling defined", d: 3, q: "Under GDPR, 'profiling' specifically refers to:", o: ["Any storage of personal data", "Any automated processing of personal data to evaluate certain personal aspects of a natural person, especially to analyse or predict performance, interests, behaviour, location", "Only marketing emails", "Only social-media tracking"], a: 1, e: "Article 4(4) GDPR defines profiling narrowly as automated evaluation of personal aspects. Storage alone is not profiling; profiling has stricter conditions especially when fully automated and producing legal effects (Art 22)." },
    { i: "2.6.8", c: "2.6", t: "Weak security questions", d: 2, q: "A common 'security question' for account recovery is your mother's maiden name. Why is this often a weak control?", o: ["It is too long to remember", "Such information is frequently public or socially discoverable, undermining the secret", "It must be encrypted twice", "Browsers cannot store it"], a: 1, e: "Genealogical and personal-history facts are often publicly inferable, defeating the 'secret' premise. MFA via authenticator app or hardware key is far stronger." },
    { i: "3.1.1", c: "3.1", t: "PDF for fixed layout", d: 1, q: "You need to send a final report that must look identical on every device and operating system. The best format is:", o: [".docx", ".pdf", ".rtf", ".txt"], a: 1, e: "PDF preserves layout, fonts, and pagination across platforms. DOCX is for editable working documents and may render differently." },
    { i: "3.1.2", c: "3.1", t: "SVG for logos", d: 2, q: "Which file format is best for a logo that must scale crisply from a business card to a billboard?", o: [".jpg", ".png", ".svg", ".gif"], a: 2, e: "SVG is vector — it scales without quality loss. JPEG and PNG are raster (pixel-based) and degrade when enlarged." },
    { i: "3.1.3", c: "3.1", t: "JPEG vs PNG", d: 1, q: "JPEG and PNG differ principally because:", o: ["JPEG is lossy compression suited to photographs; PNG is lossless and supports transparency", "PNG is older than JPEG", "JPEG cannot be displayed in browsers", "PNG is only for icons"], a: 0, e: "JPEG uses lossy compression and is well-suited to photographs. PNG is lossless and supports an alpha (transparency) channel — preferred for screenshots, line art." },
    { i: "3.1.4", c: "3.1", t: "Slide accessibility", d: 2, q: "You are creating a presentation slide deck. Which practice contributes MOST to accessibility from the start?", o: ["Using bright primary colours", "Adding alt-text to images, using built-in heading styles, and ensuring colour contrast", "Choosing an unusual font for visual interest", "Animating every slide transition"], a: 1, e: "Alt-text, structural styles (so reading order is correct), and adequate contrast align with WCAG 2.2." },
    { i: "3.1.5", c: "3.1", t: "Captions vs subtitles", d: 2, q: "Which is a defining feature of CAPTIONS as distinct from subtitles?", o: ["Captions are always in another language", "Captions include non-speech audio information (e.g. [door slams]) for deaf and hard-of-hearing viewers", "Captions are smaller font", "Captions are decorative"], a: 1, e: "Captions assume the viewer cannot hear the audio and therefore include relevant non-speech sounds. Subtitles assume hearing audiences and translate dialogue." },
    { i: "3.1.6", c: "3.1", t: "AI image disclosure", d: 3, q: "You generate an illustration with a generative-AI image tool and use it in an internal newsletter. The most professionally responsible practice is to:", o: ["Treat it as a stock image with no further consideration", "Disclose that it is AI-generated, comply with the tool's terms of use, and check for any visible problematic artefacts", "Claim it as your own original artwork", "Add a watermark of a famous artist"], a: 1, e: "Disclosure, ToS-compliance, and quality checking are converging best practice; the EU AI Act adds transparency obligations for AI-generated media." },
    { i: "3.1.7", c: "3.1", t: "PST not an image", d: 2, q: "Which file extension is NOT an image format?", o: [".png", ".jpeg", ".pst", ".gif"], a: 2, e: ".PST is a Microsoft Outlook personal-storage file (mailbox archive). PNG, JPEG, and GIF are image formats. This question type appears in the official EPSO sample set." },
    { i: "3.1.8", c: "3.1", t: "PDF accessibility", d: 2, q: "What makes a PDF accessible to screen-reader users?", o: ["A small file size", "Tagged structure (headings, reading order), embedded text (not just a scanned image), and alt-text on figures", "An attractive cover page", "High-resolution images"], a: 1, e: "Untagged or scanned-image PDFs are opaque to assistive technology. Proper tagging and embedded text are core accessibility requirements (and are part of EN 301 549 / WCAG 2.2)." },
    { i: "3.2.1", c: "3.2", t: "Plagiarism", d: 2, q: "You read a paragraph in a published study, change a few words, and use it in your report without attribution. This is:", o: ["Acceptable, because you changed words", "Plagiarism, regardless of word changes", "Original work, because the words are not identical", "Fair use in all cases"], a: 1, e: "Plagiarism is presenting another's ideas or expression as your own. Light paraphrase without attribution remains plagiarism." },
    { i: "3.2.2", c: "3.2", t: "TASL", d: 1, q: "You combine three CC-BY photos into a collage for a public report. The minimum requirement is to:", o: ["Do nothing", "Credit each photographer with title (if any), author, source, and licence (TASL)", "Email the photographers for new permission", "Convert all images to public domain"], a: 1, e: "CC-BY requires attribution. The TASL convention (Title, Author, Source, Licence) is the practical attribution standard." },
    { i: "3.2.3", c: "3.2", t: "ND derivatives", d: 2, q: "You translate a CC-BY-ND article. This is:", o: ["Always allowed", "Generally NOT allowed without separate permission, because ND prohibits derivative works", "Always allowed if you also share the translation", "Allowed if you remove attribution"], a: 1, e: "ND = NoDerivatives. A translation is a derivative work and is not permitted by CC-BY-ND. CC-BY (without ND) and CC-BY-SA permit translations." },
    { i: "3.2.4", c: "3.2", t: "AI re-use", d: 3, q: "You ask a generative-AI tool to draft a section for your report. Before integrating it, the most rigorous step is:", o: ["Paste it directly to save time", "Verify factual claims against authoritative sources, edit for accuracy and voice, and document the AI use per policy", "Translate it into another language", "Add quotation marks"], a: 1, e: "AI outputs are starting points: they require fact-checking, editorial integration, and disclosure consistent with organisational policy." },
    { i: "3.2.5", c: "3.2", t: "Mashup risk", d: 2, q: "What is a key legal risk when creating a 'mashup' of music tracks and publishing it?", o: ["The file size will be huge", "Each track is typically copyright-protected; a mashup may be an infringing derivative without licences from rights-holders", "Mashups cannot be played on phones", "The audio quality drops"], a: 1, e: "Even for non-commercial mashups, multiple layers of copyright (composition, performance, recording) usually apply. Licences or specific exceptions are needed." },
    { i: "3.2.6", c: "3.2", t: "ShareAlike", d: 1, q: "In an adapted version of a CC-BY-SA work, which is required?", o: ["Attribution and release of your adaptation under the same / compatible CC-BY-SA licence", "Removing the original author's name", "Releasing it as proprietary", "Charging a fee"], a: 0, e: "SA = ShareAlike: derivatives must be released under the same or a compatible licence. Attribution remains mandatory in all CC licences (except CC0)." },
    { i: "3.2.7", c: "3.2", t: "Embed vs copy", d: 2, q: "Which use of a YouTube video is generally lowest in copyright risk for an internal blog post?", o: ["Downloading and re-uploading the video", "Embedding the official YouTube player using the provided code, which streams from the original source", "Cropping the video and reposting", "Recording the screen while it plays"], a: 1, e: "Embedding the official player respects the platform's intended distribution and the rights-holder's controls. Downloading and re-uploading is typically infringing." },
    { i: "3.2.8", c: "3.2", t: "Translation rights", d: 3, q: "Translating a copyright-protected book without permission and posting the translation online is generally:", o: ["Permitted under fair use everywhere", "An infringement of the author's right to authorise translations (a derivative right under copyright)", "Allowed because translation is creative", "Allowed if the translation is free"], a: 1, e: "The right to authorise translations is part of copyright. Without permission or a relevant exception, public posting of an unauthorised translation is infringing." },
    { i: "3.3.1", c: "3.3", t: "CC vs copyright", d: 2, q: "Creative Commons licences are best described as:", o: ["An alternative to copyright that abolishes it", "Licences built on top of copyright that pre-authorise certain uses", "A legal exemption from copyright in the EU", "A trademark scheme"], a: 1, e: "CC licences operate within copyright, granting users specific permissions in advance. They do not replace or abolish copyright." },
    { i: "3.3.2", c: "3.3", t: "CC0 vs PDM", d: 3, q: "Which best distinguishes CC0 from the Public Domain Mark (PDM)?", o: ["They are identical", "CC0 is a deliberate dedication waiving rights to the maximum extent the law allows; PDM labels works already in the public domain (e.g. expired copyright)", "PDM is a paid licence", "CC0 requires attribution"], a: 1, e: "CC0 is an active waiver/dedication by a rights-holder. PDM is a label asserting that a work is already in the public domain through operation of law." },
    { i: "3.3.3", c: "3.3", t: "NC by use", d: 2, q: "A photo is licensed CC BY-NC. A small charity uses it on a fundraising page that asks for donations. Is this compatible?", o: ["Yes, because charities are non-commercial by nature", "It depends — 'non-commercial' is defined by the use, not the user; fundraising can be considered commercial in CC's interpretation", "No, charities can never use NC works", "Yes, because BY allows everything"], a: 1, e: "NC is defined by use: 'primarily intended for or directed toward commercial advantage or monetary compensation'. Charity status alone does not exempt the use." },
    { i: "3.3.4", c: "3.3", t: "All CC require BY", d: 1, q: "Which obligation applies to ALL six standard CC licences (CC BY, BY-SA, BY-ND, BY-NC, BY-NC-SA, BY-NC-ND)?", o: ["ShareAlike", "Non-commercial only", "Attribution", "No derivatives"], a: 2, e: "Attribution (BY) is the common element of all six licences. SA, NC and ND apply only to subsets. Only CC0 removes the attribution requirement." },
    { i: "3.3.5", c: "3.3", t: "Free to view ≠ free to reuse", d: 2, q: "You find an essay freely viewable on a personal blog. You want to republish it on your team's intranet. The correct assumption is:", o: ["Free to view = free to reuse", "Reuse requires permission or an applicable licence; visibility on the open web does not grant a licence", "All web content is in the public domain", "Internal reuse is automatically lawful"], a: 1, e: "Visibility implies no licence. Reuse needs the rights-holder's permission or an applicable exception. 'Internal' use is still reproduction." },
    { i: "3.3.6", c: "3.3", t: "Open source vs freeware", d: 2, q: "Which best distinguishes open-source software from freeware?", o: ["Open source is always free of cost; freeware is paid", "Open source grants rights to use, study, modify and redistribute the source code under a licence; freeware is gratis but typically proprietary, with no source rights", "They are the same", "Freeware is open source"], a: 1, e: "Open source = freedom to use/study/modify/redistribute the source. Freeware = zero-cost but proprietary, often with no access to source code." },
    { i: "3.3.7", c: "3.3", t: "EU copyright duration", d: 2, q: "In the EU, the standard copyright duration for a literary work is:", o: ["20 years from creation", "Life of the author + 70 years", "Indefinite", "Life of the author + 25 years"], a: 1, e: "Directive 2006/116/EC sets the standard at the life of the author + 70 years for most literary and artistic works." },
    { i: "3.3.8", c: "3.3", t: "TDM exception", d: 3, q: "The 2019 EU Directive on Copyright in the Digital Single Market introduces a text-and-data-mining (TDM) exception. For commercial actors, this exception is:", o: ["Unconditional — any reuse is allowed", "Subject to rights-holders being able to opt out by machine-readable reservation", "Limited to public-domain works", "Restricted to journalism"], a: 1, e: "Article 4 of Directive 2019/790 lets commercial actors carry out TDM unless rights-holders opt out in an appropriate machine-readable form. Article 3 grants a stronger exception for research organisations." },
    { i: "3.4.1", c: "3.4", t: "Algorithmic thinking", d: 1, q: "Algorithmic thinking is best described as:", o: ["Memorising programming syntax", "Breaking a problem into a clear sequence of unambiguous steps that can be executed mechanically", "Using AI to write code", "Buying a faster computer"], a: 1, e: "Algorithmic thinking is independent of language or tools. It is the capacity to decompose problems into stepwise, executable procedures." },
    { i: "3.4.2", c: "3.4", t: "Loops", d: 1, q: "In a recipe-style algorithm, an instruction like 'while the water is not boiling, keep heating' corresponds to:", o: ["A conditional (if statement)", "A loop with a continuation condition", "A function definition", "A constant"], a: 1, e: "'While X, do Y' is a paradigm loop construct. A conditional executes once if a condition holds; a loop repeats while/until a condition changes." },
    { i: "3.4.3", c: "3.4", t: "Pseudocode", d: 1, q: "Pseudocode is useful primarily because it:", o: ["Runs faster than real code", "Lets you describe an algorithm clearly without committing to a specific language's syntax", "Encrypts the algorithm", "Is required for compilation"], a: 1, e: "Pseudocode communicates logic to humans, language-independently. It is not executable; clarity is its purpose." },
    { i: "3.4.4", c: "3.4", t: "No-code trade-off", d: 2, q: "A 'no-code' workflow tool lets you automate office tasks without programming. The main trade-off versus traditional code is:", o: ["No-code is always faster at runtime", "No-code is more accessible but less flexible — complex or unusual logic, performance tuning, and full control require code", "No-code never has bugs", "No-code does not need testing"], a: 1, e: "No-code platforms accelerate common workflows but constrain expressiveness. Code remains essential for non-standard requirements and fine control." },
    { i: "3.4.5", c: "3.4", t: "AI is designed", d: 2, q: "DigComp 2.2 emphasises that AI systems are 'programmed by humans, with values and biases of their designers'. The practical implication for a citizen is to:", o: ["Trust AI completely because it is mathematical", "Critically appraise AI outputs and recognise that AI behaviour reflects design choices and training data", "Ignore AI entirely", "Treat AI as a neutral oracle"], a: 1, e: "DigComp 2.2's AI annex stresses that AI is not a neutral oracle. Critical appraisal — including of training data and design intent — is part of citizen-level AI literacy." },
    { i: "3.4.6", c: "3.4", t: "Debugging", d: 1, q: "A simple script does not produce the expected output. The most productive first step is to:", o: ["Rewrite from scratch", "Reproduce the problem reliably and locate the smallest input that triggers it", "Ask a colleague to write it", "Disable error messages"], a: 1, e: "Reliable reproduction and minimisation are the diagnostic foundations. Rewriting often re-introduces bugs; suppressing errors hides information." },
    { i: "3.4.7", c: "3.4", t: "Macros", d: 2, q: "You repeatedly perform a 12-step formatting routine in a spreadsheet. The most efficient automation is:", o: ["Hire someone to do it", "Record or write a macro / script that performs the steps reliably", "Print the spreadsheet", "Use a different colour"], a: 1, e: "Macros and scripts automate deterministic, repeated procedures, freeing time and reducing errors. This is exactly the kind of self-service automation DigComp 3.4 promotes." },
    { i: "3.4.8", c: "3.4", t: "AI code review", d: 3, q: "You ask a generative-AI tool to write a short script. The output runs but produces wrong results in edge cases. Which best describes the situation?", o: ["AI-generated code is always correct", "AI-generated code requires the same testing, review, and edge-case scrutiny as any human-written code", "Edge cases are unimportant", "The bug is the user's fault"], a: 1, e: "AI-generated code can be plausible-looking yet incorrect, especially for edge cases. Treat it like any other contribution: review, test, validate." },
    { i: "4.1.1", c: "4.1", t: "Smishing", d: 2, q: "You receive a personalised SMS that pretends to be from your bank, with your name and last digits of an account. This is best described as:", o: ["Whaling", "Smishing (SMS phishing) — a targeted variant", "Vishing", "Spoofing alone"], a: 1, e: "Smishing = phishing over SMS. Whaling targets executives; vishing is voice-based; spoofing alone refers to forging identity, not the act of soliciting." },
    { i: "4.1.2", c: "4.1", t: "Phishing vs spoofing", d: 3, q: "Spoofing and phishing are related but distinct concepts. Which statement is most accurate?", o: ["Spoofing is forging an identity (e.g. email header, caller ID); phishing is the attack of tricking someone into giving up credentials, often using spoofing", "They are synonymous", "Spoofing is always a hardware attack", "Phishing only happens via email"], a: 0, e: "Spoofing is a technique (forging identity); phishing is an attack pattern (eliciting credentials/information). Phishing often uses spoofing, but each can occur without the other." },
    { i: "4.1.3", c: "4.1", t: "MFA factors", d: 1, q: "Multi-factor authentication adds a layer of security by requiring:", o: ["Two passwords", "Authentication factors from at least two different categories: knowledge, possession, inherence", "Two email addresses", "Two browsers"], a: 1, e: "MFA combines factors of different kinds: something you know (password), have (token, phone), are (biometric). Two passwords are still one factor." },
    { i: "4.1.4", c: "4.1", t: "SMS 2FA weakness", d: 2, q: "Compared to SMS-based 2FA, authenticator apps and hardware keys are generally:", o: ["Less secure", "More resistant to SIM-swap and to certain phishing techniques", "Identical in security", "Only for IT staff"], a: 1, e: "SMS codes can be intercepted via SIM-swap and SS7 attacks, and are phishable. TOTP apps and especially FIDO2/WebAuthn hardware keys raise the bar substantially." },
    { i: "4.1.5", c: "4.1", t: "At rest vs in transit", d: 3, q: "Your laptop has full-disk encryption and your browser uses HTTPS. Which statement is correct?", o: ["The laptop is protected at rest; HTTPS protects data in transit between you and the website — both layers are needed", "HTTPS makes disk encryption redundant", "Disk encryption protects you from network eavesdropping", "Both terms describe the same control"], a: 0, e: "Encryption at rest protects stored data if the device is lost or stolen. Encryption in transit (TLS/HTTPS) protects data crossing networks. Each addresses a different threat." },
    { i: "4.1.6", c: "4.1", t: "HTTPS limits", d: 2, q: "A website has a valid HTTPS padlock. What does this guarantee?", o: ["The site is GDPR-compliant", "The site is honest", "Communication between your browser and the server is encrypted, and the server's domain has been validated by a certificate authority", "Nothing"], a: 2, e: "HTTPS encrypts the channel and authenticates the domain. It does not prove the site's owner is honest, lawful, or compliant — phishing sites routinely use HTTPS." },
    { i: "4.1.7", c: "4.1", t: "Public Wi-Fi", d: 2, q: "You must work from a café using public Wi-Fi. The most prudent baseline is to:", o: ["Disable HTTPS to save bandwidth", "Use the institution's VPN, ensure HTTPS for all sites, and avoid logins to highly sensitive systems where possible", "Trust the network because the password is shared", "Use only your phone's Bluetooth"], a: 1, e: "VPN + HTTPS combine encryption layers; minimising sensitive logins reduces blast radius." },
    { i: "4.1.8", c: "4.1", t: "Patching", d: 1, q: "Which is the single highest-leverage hygiene control for most organisations?", o: ["Buying expensive antivirus", "Promptly applying operating-system and application security updates", "Changing the company logo", "Adding more firewalls"], a: 1, e: "Most successful breaches exploit known, unpatched vulnerabilities. Timely patching is consistently rated by ENISA, NCSC and CISA as the top-leverage control." },
    { i: "4.2.1", c: "4.2", t: "Controller vs processor", d: 3, q: "Your unit at the Commission contracts a private cloud provider to host citizen feedback survey data. Under GDPR, who must notify the supervisory authority within 72 hours of a personal-data breach on the cloud provider's systems?", o: ["The cloud provider, because the breach happened on its systems", "Only the cloud provider's data-protection officer", "Your unit (the controller), informed of the breach by the cloud provider (the processor)", "No-one — internal documentation suffices"], a: 2, e: "The Article 33 obligation is on the controller. The processor must inform the controller 'without undue delay' under Art 33(2). The 72-hour clock runs from the controller's awareness." },
    { i: "4.2.2", c: "4.2", t: "GDPR principles", d: 2, q: "Which is NOT one of the GDPR principles in Article 5?", o: ["Purpose limitation", "Data minimisation", "Mandatory cross-border transfer", "Storage limitation"], a: 2, e: "Article 5 lists: lawfulness/fairness/transparency, purpose limitation, data minimisation, accuracy, storage limitation, integrity and confidentiality, accountability." },
    { i: "4.2.3", c: "4.2", t: "Lawful bases", d: 3, q: "Which is NOT a recognised lawful basis under Article 6 GDPR for processing personal data?", o: ["Consent", "Performance of a contract with the data subject", "Best commercial interest of any competitor", "Compliance with a legal obligation"], a: 2, e: "The six bases are: consent, contract, legal obligation, vital interests, public task, legitimate interests. Generic commercial interest of a third party is not a basis." },
    { i: "4.2.4", c: "4.2", t: "Pseudonymisation", d: 3, q: "Pseudonymised data under GDPR is:", o: ["Outside GDPR scope", "Still personal data, because re-identification is possible with additional information", "The same as anonymised data", "Always sensitive data"], a: 1, e: "Pseudonymised data remain personal data because the link can be restored. Only fully anonymised data falls outside GDPR." },
    { i: "4.2.5", c: "4.2", t: "Special-category", d: 2, q: "Which counts as 'special-category' data under Article 9 GDPR?", o: ["A person's name", "A person's professional email", "A person's health data", "A person's office number"], a: 2, e: "Article 9 lists: racial/ethnic origin, political opinions, religious beliefs, trade-union membership, genetic, biometric for identification, health, sex life, sexual orientation." },
    { i: "4.2.6", c: "4.2", t: "72-hour rule", d: 3, q: "GDPR requires notification of a personal-data breach to the supervisory authority:", o: ["Within 24 hours, always", "Within 72 hours of becoming aware, where feasible — unless the breach is unlikely to result in a risk to rights and freedoms", "Within 30 days", "Only if more than 1000 people are affected"], a: 1, e: "Article 33: notify the supervisory authority within 72 hours where feasible, with reasoned justification if delayed, unless the breach is unlikely to result in a risk to rights and freedoms." },
    { i: "4.2.7", c: "4.2", t: "Erasure not absolute", d: 2, q: "Which is NOT a data subject right under GDPR?", o: ["Right of access", "Right to rectification", "Right to demand deletion of any data without exception", "Right to data portability"], a: 2, e: "The right to erasure (Art 17) has explicit grounds and exceptions (e.g. freedom of expression, legal obligation, public interest). It is not unconditional." },
    { i: "4.2.8", c: "4.2", t: "Cookie consent", d: 2, q: "Under EU rules (ePrivacy + GDPR), valid cookie consent for non-essential cookies must be:", o: ["Pre-ticked by default for user convenience", "Freely given, specific, informed and unambiguous, by a clear affirmative action", "Implied by continued browsing", "Buried in a privacy policy"], a: 1, e: "The CJEU's Planet49 ruling and EDPB guidance confirm that pre-ticked boxes and continued browsing are not valid consent. A clear opt-in action is required." },
    { i: "4.3.1", c: "4.3", t: "Right to disconnect", d: 2, q: "The 'right to disconnect' refers to:", o: ["A right to switch off your antivirus", "A worker's right not to engage in work-related electronic communication outside working hours", "A right to use only one device", "A right to public Wi-Fi"], a: 1, e: "The right to disconnect is recognised in EU labour-policy debate and in DigComp 2.2's RW examples. Several Member States have legislated it explicitly." },
    { i: "4.3.2", c: "4.3", t: "Dark patterns", d: 3, q: "A subscription page makes it easy to subscribe but hides the cancellation flow behind multiple confusing screens. This is an example of:", o: ["Good UX", "A 'dark pattern' (deceptive design), regulated under the EU Digital Services Act and Unfair Commercial Practices framework", "A privacy-by-design feature", "An accessibility improvement"], a: 1, e: "Asymmetric friction between sign-up and cancellation is a textbook dark pattern. The DSA explicitly prohibits dark patterns on online platforms." },
    { i: "4.3.3", c: "4.3", t: "Bystander cyberbullying", d: 1, q: "A colleague shows you sustained, repeated, hostile messages they are receiving on a public team channel. The most appropriate professional response is to:", o: ["Tell them to ignore it", "Acknowledge the harm, encourage them to preserve evidence (screenshots), and support them in reporting through formal channels", "Reply publicly with insults of your own", "Delete the messages on their behalf"], a: 1, e: "Acknowledgement, evidence preservation, and formal reporting are the recognised support pattern. Counter-attacks escalate; deletion may destroy evidence." },
    { i: "4.3.4", c: "4.3", t: "Ergonomics", d: 1, q: "Which practice best supports physical well-being during long computer-based work?", o: ["Working in dim ambient light to 'rest' the eyes", "Following a regular routine of breaks (e.g. 20-20-20 rule), correct chair/screen height, and varied posture", "Disabling all notifications", "Closing the curtains"], a: 1, e: "Regular breaks, ergonomic setup, and varied posture are well-evidenced. Dim light actually increases eye strain by widening the contrast with a bright screen." },
    { i: "4.3.5", c: "4.3", t: "Loot boxes", d: 2, q: "A 'free' mobile game uses 'loot boxes' that deliver random rewards in exchange for in-app currency. The principal well-being concern is:", o: ["The graphics are too colourful", "The mechanic uses variable-ratio reinforcement similar to gambling, with documented risks especially for younger users", "The game has too few levels", "It uses too much battery"], a: 1, e: "Loot boxes share psychological mechanics with gambling and are regulated as gambling in some Member States." },
    { i: "4.3.6", c: "4.3", t: "Notification hygiene", d: 1, q: "A common evidence-based recommendation for digital well-being and focus is to:", o: ["Enable all notifications to stay informed", "Selectively disable non-essential notifications and batch-check messages at intervals", "Keep the phone in your hand at all times", "Use only one app"], a: 1, e: "Constant interruptions degrade attention and increase stress. Selective notifications and batched checking are widely recommended in workplace digital-wellbeing guidance." },
    { i: "4.3.7", c: "4.3", t: "Harassment pattern", d: 2, q: "What pattern most reliably distinguishes online harassment from a single offensive comment?", o: ["The use of capital letters", "Repetition, persistence, and a power imbalance — features that align with workplace anti-harassment definitions", "The presence of emoji", "A long message"], a: 1, e: "Harassment frameworks (e.g. EU-OSHA, ILO) emphasise repetition and unwanted, hostile pattern, often with power imbalance — distinct from one-off rudeness." },
    { i: "4.3.8", c: "4.3", t: "Persuasive design", d: 3, q: "Infinite-scroll feeds, pull-to-refresh, and streak counters are examples of:", o: ["Accessibility features", "Persuasive-design patterns engineered to maximise time-on-app, with documented attentional and well-being trade-offs", "Encryption protocols", "Privacy-by-design tools"], a: 1, e: "Persuasive design borrows from behavioural psychology to drive engagement. DigComp 2.2 explicitly raises awareness of these patterns and their well-being effects." },
    { i: "4.4.1", c: "4.4", t: "WEEE", d: 1, q: "What is the recommended end-of-life route for an old laptop with personal data on it?", o: ["Throw it in the household bin", "Securely wipe the storage (or destroy it), then recycle through a certified WEEE / e-waste channel", "Leave it on the street", "Bury it"], a: 1, e: "WEEE channels recover materials and prevent toxic releases. Secure data deletion or physical destruction protects personal data first." },
    { i: "4.4.2", c: "4.4", t: "Video footprint", d: 2, q: "Which choice typically reduces the energy footprint of a video conference?", o: ["Higher resolution always", "Turning off video when it is not needed for interaction; lowering resolution; preferring audio-only when sufficient", "Adding more participants", "Recording every call"], a: 1, e: "Video streams dominate bandwidth and indirectly energy consumption. Voice-only and lower-resolution options are simple, well-recognised reductions." },
    { i: "4.4.3", c: "4.4", t: "AI energy", d: 2, q: "Training large AI models is energy-intensive. A reasonable consumer-level practice that supports environmental sustainability is to:", o: ["Use the largest model for every trivial query", "Match the model size and tool to the task — use smaller / lighter tools where they suffice", "Always run multiple models in parallel", "Train your own model for every question"], a: 1, e: "Right-sizing the tool to the task (smaller LLMs, deterministic tools where applicable) reduces compute and energy use without sacrificing utility." },
    { i: "4.4.4", c: "4.4", t: "Right to repair", d: 2, q: "The EU's 'right to repair' policy aims primarily to:", o: ["Make all repairs free", "Extend product lifetimes by ensuring access to spare parts, repair information, and reasonable repair conditions", "Ban repairs by amateurs", "Replace recycling"], a: 1, e: "Right to repair (Directive 2024/1799) facilitates repair of consumer goods, supporting circular-economy goals." },
    { i: "4.4.5", c: "4.4", t: "Cloud carbon", d: 2, q: "Choosing a cloud provider whose data centre runs primarily on renewable energy is one way to:", o: ["Avoid GDPR", "Reduce the carbon footprint of digital services", "Increase storage by 10x", "Disable encryption"], a: 1, e: "Energy mix of underlying data centres is a recognised lever in green-IT procurement." },
    { i: "4.4.6", c: "4.4", t: "Ecodesign", d: 2, q: "The EU Ecodesign for Sustainable Products Regulation (ESPR, 2024) for digital products encourages:", o: ["Single-use design", "Durability, reparability, recyclability, and access to firmware updates", "Mandatory annual replacement", "Closed proprietary chargers"], a: 1, e: "ESPR aims at extending product lifetimes and reducing material waste, including for electronics." },
    { i: "4.4.7", c: "4.4", t: "Print vs digital", d: 1, q: "For a one-page leaflet read once and discarded, the lowest-impact distribution is typically:", o: ["Glossy printed full-colour mass mail", "A digital version delivered to those who actually want it, with print on demand for those who prefer paper", "Printing one copy per resident always", "No distribution at all"], a: 1, e: "Targeted digital distribution avoids material waste; print-on-demand respects accessibility preferences." },
    { i: "4.4.8", c: "4.4", t: "Lifecycle impact", d: 2, q: "From a sustainability perspective, the highest-impact decision over a laptop's lifecycle is usually:", o: ["The brand's logo colour", "Whether it is replaced every two years vs every five years", "The keyboard layout", "The screen brightness setting"], a: 1, e: "Manufacturing dominates lifecycle impact for most consumer electronics. Extending replacement cycles delivers a larger reduction than most operational tweaks." },
    { i: "5.1.1", c: "5.1", t: "First-line", d: 1, q: "A colleague's laptop will not connect to Wi-Fi. The most efficient first-line steps are:", o: ["Reformat the disk immediately", "Check airplane mode / Wi-Fi switch, restart the network adapter, check the network is up for others", "Buy a new laptop", "Reinstall the operating system"], a: 1, e: "The fastest fixes address the most common causes (mode switches, transient adapter state, network outages)." },
    { i: "5.1.2", c: "5.1", t: "Error codes", d: 2, q: "An application shows a cryptic error code. The most productive next step is:", o: ["Ignore it", "Note the exact wording and code, then search for it in official documentation or the vendor's knowledge base", "Click randomly until it disappears", "Restart five times in a row"], a: 1, e: "Error codes are searchable identifiers. Capturing the exact wording lets you find vendor documentation or known-issue threads efficiently." },
    { i: "5.1.3", c: "5.1", t: "Browser-side state", d: 2, q: "A web app works for colleagues but not for you. As a quick test, you should try:", o: ["Reinstalling Windows", "Clearing browser cache and cookies for the site, or trying a private window / different browser", "Replacing the keyboard", "Disabling antivirus and firewall"], a: 1, e: "Stale cache, expired cookies, and corrupted local state are common causes of 'works for them, not for me'. A private window isolates the variable cleanly." },
    { i: "5.1.4", c: "5.1", t: "DNS isolation", d: 3, q: "You can ping google.com but cannot reach the website in your browser. The most likely culprit is:", o: ["A browser-layer or proxy issue (since name resolution itself succeeded)", "A faulty graphics card", "No-one else uses the internet", "Your printer driver"], a: 0, e: "If ping resolves the name and reaches the host, name resolution is fine but a browser-layer or proxy issue is likely. The point is to isolate layers." },
    { i: "5.1.5", c: "5.1", t: "Hardware vs software", d: 2, q: "Your screen flickers in every application. Which test best distinguishes hardware from software causes?", o: ["Boot from a different OS / live USB and observe the same monitor", "Try a different keyboard", "Reinstall one application", "Close the laptop lid"], a: 0, e: "Booting an alternative OS isolates whether the symptom follows the hardware or the OS install. If flicker persists, hardware is implicated." },
    { i: "5.1.6", c: "5.1", t: "Ransomware response", d: 1, q: "A laptop displays a serious-looking warning that it has been encrypted by ransomware demanding payment. You should:", o: ["Pay quickly to minimise data loss", "Disconnect the device from the network and immediately escalate to IT / security, do not pay", "Format the disk yourself", "Forward the warning to colleagues"], a: 1, e: "Containment first (network isolation), then expert response. Paying funds criminal operations, gives no guarantee, and may trigger legal/sanctions issues." },
    { i: "5.1.7", c: "5.1", t: "Cross-browser", d: 2, q: "A web app behaves wrongly in one browser but works in another. The most likely cause is:", o: ["Defective hardware", "A browser-specific compatibility, extension, or cache issue", "A virus", "A faulty router"], a: 1, e: "Cross-browser differences narrow the issue to browser-side state or compatibility." },
    { i: "5.1.8", c: "5.1", t: "Documentation", d: 2, q: "You solve a tricky issue after a long search. The professional next step is to:", o: ["Forget about it", "Document the symptom, root cause and fix in a place your team can find later", "Email the manufacturer", "Hide the documentation"], a: 1, e: "Documenting solved issues builds organisational memory and saves future hours. DigComp 5.4 also frames this as supporting others." },
    { i: "5.2.1", c: "5.2", t: "IaaS/PaaS/SaaS", d: 3, q: "Which best matches the cloud service models?", o: ["IaaS = applications, PaaS = storage, SaaS = networks", "IaaS = raw infrastructure (VMs, storage), PaaS = managed platform to develop and deploy apps, SaaS = ready-to-use applications over the web", "IaaS, PaaS and SaaS are the same", "IaaS is for individuals only"], a: 1, e: "IaaS rents infrastructure. PaaS provides a managed platform. SaaS delivers complete applications. Each shifts more responsibility to the provider." },
    { i: "5.2.2", c: "5.2", t: "Cloud vs edge", d: 3, q: "Edge computing differs from cloud computing principally because it:", o: ["Is more expensive", "Processes data near where it is produced (e.g. on or close to IoT devices) to reduce latency and bandwidth use", "Cannot be encrypted", "Requires no electricity"], a: 1, e: "Edge computing brings computation closer to the data source. Latency-sensitive (industrial, medical, automotive) and bandwidth-constrained scenarios benefit." },
    { i: "5.2.3", c: "5.2", t: "RPA fit", d: 2, q: "Your unit processes hundreds of identical form responses each week. The best fit is generally:", o: ["Hire more staff", "An automated workflow / RPA / scripting solution with human review of edge cases", "A new printer", "Manual triple-checking"], a: 1, e: "Repetitive, rule-based work is a textbook automation target. Keeping humans in the loop for exceptions preserves judgement where it adds value." },
    { i: "5.2.4", c: "5.2", t: "Tool to task", d: 1, q: "Which is the most appropriate tool for occasional collaborative editing of a short text?", o: ["A relational database", "A shared cloud document with track changes", "A 3D modelling program", "A spreadsheet macro"], a: 1, e: "Match tool to task: a shared text document is the right fit. Databases, modelling tools and macros are over-engineered for short collaborative text." },
    { i: "5.2.5", c: "5.2", t: "Accessible content", d: 2, q: "You need to share information with a user who relies on a screen reader. The best presentation is:", o: ["A scanned-image PDF of a poster", "A properly tagged document or web page with semantic structure and alt-text", "A handwritten note", "An audio file with no transcript"], a: 1, e: "Tagged, semantic content is fully perceivable to assistive technology. Image-only PDFs and untranscribed audio are inaccessible by default." },
    { i: "5.2.6", c: "5.2", t: "AI vs deterministic", d: 3, q: "You need to extract a known fixed pattern (e.g. all dates in DD/MM/YYYY format) from a large file. The most appropriate tool is generally:", o: ["A generative AI chatbot processing the file", "A deterministic tool (regular expression / parser) — exact, fast, reproducible", "A handwritten lookup", "A new database"], a: 1, e: "Where the rule is exact and stable, deterministic methods beat probabilistic ones on accuracy, speed, cost, and reproducibility. AI is best where rules are fuzzy." },
    { i: "5.2.7", c: "5.2", t: "Storage choice", d: 1, q: "Which is the most suitable storage choice for a 5 GB working dataset shared by a small team that edits it daily?", o: ["Email attachments", "A shared cloud folder or team drive with versioning and access control", "Personal USB sticks", "Print-outs in a binder"], a: 1, e: "Daily collaborative editing needs a single source of truth, version history, and controlled access — the value proposition of a team drive." },
    { i: "5.2.8", c: "5.2", t: "Audit logs", d: 2, q: "Your manager requests a chronological view of who did what on a long project. The best response is to:", o: ["Ask everyone to remember", "Provide an export from the project tool's audit / activity log", "Recreate it manually from email", "Take a photo of the wall planner"], a: 1, e: "Modern collaboration tools maintain audit / activity logs precisely for accountability." },
    { i: "5.3.1", c: "5.3", t: "AI for ideation", d: 2, q: "Used responsibly, a generative-AI tool is most useful in early creative work as:", o: ["A definitive expert that decides", "A divergent ideation partner — to broaden options that you then evaluate critically", "A replacement for any expertise", "A neutral source of facts"], a: 1, e: "Generative AI is best treated as a divergent thinking aid: produce many options, then apply human judgement, expertise, and verification." },
    { i: "5.3.2", c: "5.3", t: "IoT example", d: 2, q: "A municipality deploys soil-moisture sensors in parks to optimise irrigation. This is an example of:", o: ["Generative AI", "An Internet-of-Things (IoT) deployment — networked sensors feeding a control system", "A blockchain", "Quantum computing"], a: 1, e: "IoT = networked physical sensors/actuators producing data for analysis or control. This is a textbook smart-city example." },
    { i: "5.3.3", c: "5.3", t: "Prototyping", d: 1, q: "In design thinking, the purpose of a prototype is principally to:", o: ["Be the final product", "Make ideas tangible cheaply enough to test assumptions and learn before full commitment", "Replace user research", "Save engineering time later"], a: 1, e: "Prototypes exist to be tested and discarded if needed. Their value is the speed of learning, not the polish of the artefact." },
    { i: "5.3.4", c: "5.3", t: "Citizen science", d: 2, q: "Citizen-science platforms (e.g. for biodiversity monitoring) rely on members of the public contributing observations. Their main value is:", o: ["Replacing professional scientists", "Scaling data collection geographically and temporally beyond what professionals alone can cover, with appropriate quality controls", "Giving free advertising", "Reducing public consultations"], a: 1, e: "Citizen science complements professional science by extending coverage. Quality control (training, validation, redundancy) is essential." },
    { i: "5.3.5", c: "5.3", t: "AR vs VR", d: 2, q: "Augmented reality differs from virtual reality because:", o: ["AR is in 2D, VR in 3D", "AR overlays digital content onto the real-world view; VR replaces the view with a fully synthetic environment", "AR uses no sensors", "VR is older"], a: 1, e: "AR augments reality with overlays. VR replaces the user's visual environment entirely. Mixed reality (MR) blends the two." },
    { i: "5.3.6", c: "5.3", t: "Hackathon", d: 1, q: "A hackathon is best understood as:", o: ["An intentional cyber-attack exercise on production systems", "A time-bounded event where teams rapidly prototype solutions to a problem, often for learning, recruitment, or innovation", "A long-term consulting project", "A regulatory audit"], a: 1, e: "'Hack' here means rapid creation, not intrusion. Hackathons emphasise speed, collaboration, and exploratory prototyping." },
    { i: "5.3.7", c: "5.3", t: "Responsible AI deployment", d: 3, q: "Your team wants to deploy an AI tool to triage citizen complaints automatically. The most responsible approach is to:", o: ["Deploy and announce later", "Pilot with human oversight, evaluate fairness and accuracy on representative data, document the system, ensure recourse, and comply with the EU AI Act", "Hide the deployment", "Skip evaluation to save time"], a: 1, e: "Pilot, evaluate on representative data, document, and provide recourse — aligned with both DigComp 2.2 AI annex and the EU AI Act high-risk system obligations." },
    { i: "5.3.8", c: "5.3", t: "Simulation", d: 2, q: "A simulation is most useful when:", o: ["You can cheaply test an idea in the real world", "Real-world testing is too costly, slow, or risky, and a model can capture the relevant dynamics", "You want to avoid documentation", "You only need a static report"], a: 1, e: "Simulations shine where reality is too costly or risky to probe directly (epidemics, evacuations, crash testing, climate)." },
    { i: "5.4.1", c: "5.4", t: "Self-assessment tools", d: 1, q: "Tools like DigCompSAT and MyDigiSkills are intended to:", o: ["Replace formal qualifications", "Help citizens self-assess digital competence against the DigComp framework and identify learning needs", "Test employers", "Issue legally binding certificates"], a: 1, e: "They are self-assessment instruments aligned with DigComp. They support reflection and learning planning rather than formal certification." },
    { i: "5.4.2", c: "5.4", t: "Lifelong learning", d: 1, q: "Which mindset best supports keeping digital competence current?", o: ["Learn once, never update", "Treat digital competence as a continuous process of small updates, with regular self-review and exposure to new tools", "Avoid new tools", "Wait for an employer to retrain you"], a: 1, e: "Continuous, low-friction learning is more sustainable than rare crash courses. DigComp 5.4 frames competence as a moving target tied to lifelong learning." },
    { i: "5.4.3", c: "5.4", t: "Micro-credentials", d: 2, q: "A 'micro-credential' is best described as:", o: ["A counterfeit diploma", "A small, verifiable certification of a specific skill or learning outcome, often issued digitally and stackable", "A government grant", "A type of password"], a: 1, e: "Micro-credentials (Council Recommendation 2022/C 243/02) are short, verifiable certifications stackable into broader qualifications." },
    { i: "5.4.4", c: "5.4", t: "Targeted learning", d: 1, q: "You realise you struggle with cybersecurity concepts. The most productive response is to:", o: ["Ignore the gap", "Take a structured course or self-paced resource (e.g. ENISA materials, MOOCs) targeting that area, and practise", "Avoid using computers", "Hire a permanent assistant"], a: 1, e: "Targeted, structured learning closes specific gaps. Avoidance compounds the problem and is professionally limiting." },
    { i: "5.4.5", c: "5.4", t: "Supporting others", d: 2, q: "DigComp 5.4 also includes 'supporting others'. A practical application is to:", o: ["Do everyone else's work", "Mentor a less-experienced colleague, or document a process so others can use it independently", "Hide your knowledge", "Avoid teaching"], a: 1, e: "Mentoring and documentation are cited as part of the competence. They scale the team's capability and reinforce one's own understanding." },
    { i: "5.4.6", c: "5.4", t: "AI/data trends", d: 2, q: "Why is staying current with AI and data trends specifically called out in DigComp 2.2?", o: ["Because trends are unimportant", "Because AI and data practices are evolving rapidly and have direct effects on rights, work, and decisions citizens encounter", "Because it is fashionable", "Because DigComp will be replaced"], a: 1, e: "DigComp 2.2's emphasis on AI literacy reflects the speed of change and the consequential effects on individuals." },
    { i: "5.4.7", c: "5.4", t: "MOOCs", d: 1, q: "A MOOC (Massive Open Online Course) is best characterised as:", o: ["A face-to-face seminar", "An online course typically open at scale, often free or low-cost, sometimes with optional paid certification", "A private tutoring service", "A new programming language"], a: 1, e: "MOOCs are scalable open online courses, often hosted on platforms like Coursera, edX, FutureLearn, or the EU's own initiatives." },
    { i: "5.4.8", c: "5.4", t: "Blind spots", d: 2, q: "Which approach is most likely to reveal blind spots in your digital competence?", o: ["Only doing tasks you already know well", "Periodically tackling unfamiliar tools, peer feedback, and structured self-assessment", "Avoiding feedback", "Working alone"], a: 1, e: "Stretch tasks, feedback, and assessments expose unknown unknowns. Routine alone tends to reinforce existing patterns and hides gaps." }
];

window.AREAS = [
    { n: 1, name: "Information & data literacy", roman: "I", competences: [{ c: "1.1", name: "Browsing, searching and filtering" }, { c: "1.2", name: "Evaluating data and content" }, { c: "1.3", name: "Managing data and content" }] },
    { n: 2, name: "Communication & collaboration", roman: "II", competences: [{ c: "2.1", name: "Interacting through digital tech" }, { c: "2.2", name: "Sharing through digital tech" }, { c: "2.3", name: "Engaging citizenship" }, { c: "2.4", name: "Collaborating through digital tech" }, { c: "2.5", name: "Netiquette" }, { c: "2.6", name: "Managing digital identity" }] },
    { n: 3, name: "Digital content creation", roman: "III", competences: [{ c: "3.1", name: "Developing digital content" }, { c: "3.2", name: "Integrating and re-elaborating" }, { c: "3.3", name: "Copyright and licences" }, { c: "3.4", name: "Programming" }] },
    { n: 4, name: "Safety", roman: "IV", competences: [{ c: "4.1", name: "Protecting devices" }, { c: "4.2", name: "Protecting personal data and privacy" }, { c: "4.3", name: "Protecting health and well-being" }, { c: "4.4", name: "Protecting the environment" }] },
    { n: 5, name: "Problem solving", roman: "V", competences: [{ c: "5.1", name: "Solving technical problems" }, { c: "5.2", name: "Identifying needs and responses" }, { c: "5.3", name: "Creatively using digital tech" }, { c: "5.4", name: "Identifying competence gaps" }] }
];
